function Login() {
  return (
    <div className="container">
      <h2>Login</h2>
      <input type="email" placeholder="Email" />
      <input type="password" placeholder="Password" />
      <button>Login</button>

      <div className="link">
        Don't have an account? <a href="/register">Register</a>
      </div>
    </div>
  );
}

export default Login;
